previewCss:
.darma-loader-loading-io-03 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
      min-width: 60px;
      min-height: 24px;
    }
    .darma-loader-loading-io-03 i {
      display: block;
      width: 12px;
      height: 12px;
      border-radius: 50%;
      background: var(--loader-color);
      animation: darma-loader-loading-io-03-dotPulse 1.05s ease-in-out infinite;
    }
    .darma-loader-loading-io-03 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loading-io-03 i:nth-child(2) { animation-delay: 0.12s; }
.darma-loader-loading-io-03 i:nth-child(3) { animation-delay: 0.24s; }
    @keyframes darma-loader-loading-io-03-dotPulse { 0%, 80%, 100% { transform: translateY(0) scale(.75); opacity: .45; } 40% { transform: translateY(-8px) scale(1); opacity: 1; } }

